#!/usr/bin/env node
/**
 * mirror-business-info.mjs
 *
 * One-way mirror: gemni-investigate (TS master) → standalone (JS mirror).
 * Strips TypeScript syntax (type annotations, `as const`, type-only exports)
 * and rewrites the file header to mark the destination as auto-generated.
 *
 * Usage (from anywhere):
 *   node scripts/mirror-business-info.mjs
 *
 * Override paths via env vars if your folders move:
 *   MASTER=/abs/path/businessInfo.ts MIRROR=/abs/path/businessInfo.canonical.js \
 *     node scripts/mirror-business-info.mjs
 */
import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const MASTER =
  process.env.MASTER ??
  resolve(
    'C:/Users/genew/gemni-investigate/src/lib/businessInfo.ts',
  );

const MIRROR =
  process.env.MIRROR ??
  resolve(
    'C:/Users/genew/Downloads/jworden_netlify_standalone_patched (2) (1)/src/lib/businessInfo.canonical.js',
  );

if (!existsSync(MASTER)) {
  console.error(`[mirror] MASTER not found: ${MASTER}`);
  process.exit(1);
}

let src = readFileSync(MASTER, 'utf8');

// 1) Strip the TS file header — we'll prepend a JS-mirror header instead.
src = src.replace(/^\/\*\*[\s\S]*?\*\/\s*/, '');

// 2) Strip `as const` annotations.
src = src.replace(/\s+as\s+const/g, '');

// 3) Strip explicit type annotations on top-level `export const X: T = …`.
src = src.replace(/^(export\s+const\s+[A-Za-z0-9_]+)\s*:\s*[^=]+=/gm, '$1 =');

// 4) Strip type-only `export type` blocks.
src = src.replace(/^export\s+type\s+[\s\S]*?;\s*$/gm, '');

// 5) Strip `export interface Name { … }` blocks (TS-only, no JS equivalent).
src = src.replace(/^export\s+interface\s+\w+\s*\{[\s\S]*?^\}\s*$/gm, '');

// 6) Strip type annotations on local `const X: T = …` declarations
//    (e.g. compile-time shape-check helpers).
src = src.replace(/^(const\s+[A-Za-z0-9_]+)\s*:\s*[A-Za-z0-9_<>[\]\s.,'"`|&]+\s*=/gm, '$1 =');

// 7) Drop standalone `void identifier;` discard statements (TS-only no-ops).
src = src.replace(/^void\s+\w+;\s*$/gm, '');

// 8) Collapse the runs of blank lines our stripping leaves behind.
src = src.replace(/\n{3,}/g, '\n\n');

const today = new Date().toISOString().slice(0, 10);

const header = `/**
 * businessInfo.canonical.js — AUTO-GENERATED MIRROR. DO NOT HAND-EDIT.
 *
 * MASTER: gemni-investigate/src/lib/businessInfo.ts
 * MIRROR REGENERATED BY: scripts/mirror-business-info.mjs
 * Last mirrored: ${today}
 *
 * To change values: edit the master TypeScript file, then re-run the mirror.
 */
`;

const out = header + '\n' + src.trimStart();

mkdirSync(dirname(MIRROR), { recursive: true });
writeFileSync(MIRROR, out, 'utf8');

console.log(`[mirror] OK\n  master  ${MASTER}\n  mirror  ${MIRROR}\n  bytes   ${out.length}`);
